import { Slot } from "@radix-ui/react-slot";
import { cva, type VariantProps } from "class-variance-authority";
import * as React from "react";

import { cn } from "@/shared/lib/utils";
import { SpinnerIcon } from "../icons/spinner-icon";

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-[var(--radius)] font-medium font-new-sans text-sm leading-[1.5] transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring active:scale-[0.98] disabled:pointer-events-none disabled:opacity-50",
  {
    variants: {
      variant: {
        default:
          "bg-primary text-primary-foreground shadow-sm hover:opacity-95",
        destructive:
          "border-[1.5px] border-[hsl(var(--destructive))] bg-transparent text-[hsl(var(--destructive))] hover:bg-[hsl(var(--destructive))]/5",
        destructiveSolid:
          "bg-[hsl(var(--destructive))] text-white hover:opacity-90",
        outline:
          "border-[1.5px] border-[hsl(var(--outline-gray))] bg-transparent text-[hsl(var(--outline-text))] hover:bg-black/5",
        secondary:
          "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        ghost: "hover:bg-accent hover:text-accent-foreground",
        link: "text-primary underline-offset-4 hover:underline",
        simple:
          "bg-transparent text-[hsl(var(--outline-text))] hover:bg-transparent hover:opacity-95",
      },
      size: {
        default: "h-[48px] px-6 py-[12px]",
        sm: "h-9 px-3",
        lg: "h-[56px] px-10 text-base",
        icon: "size-[48px]",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  },
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean;
  loading?: boolean;
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  (
    {
      className,
      variant,
      size,
      asChild = false,
      loading = false,
      disabled,
      children,
      ...props
    },
    ref,
  ) => {
    const Comp = asChild ? Slot : "button";
    return (
      <Comp
        className={cn(buttonVariants({ variant, size, className }))}
        ref={ref}
        disabled={loading || disabled}
        {...props}
      >
        {asChild ? (
          children
        ) : (
          <>
            {loading && <SpinnerIcon className="size-4 animate-spin" />}
            {children}
          </>
        )}
      </Comp>
    );
  },
);
Button.displayName = "Button";

export { Button, buttonVariants };

