321	type SortKey = "date" | "category" | "related" | "subject" | "status";
322	type SortDir = "asc" | "desc";
323	
324	interface ColumnDef {
325	  label: string;
326	  sortKey?: SortKey;
327	}
328	
329	const COLUMNS: ColumnDef[] = [
330	  { label: "Ticket ID" },
331	  { label: "Date", sortKey: "date" },
332	  { label: "Issue Category", sortKey: "category" },
333	  { label: "Related", sortKey: "related" },
334	  { label: "Description", sortKey: "subject" },
335	  { label: "Status", sortKey: "status" },
336	  { label: "Actions" },
337	];
338	
339	function sortTickets(
340	  tickets: TicketListItem[],
341	  key: SortKey,
342	  dir: SortDir
343	): TicketListItem[] {
344	  return [...tickets].sort((aa, bb) => {
345	    let cmp = 0;
346	    if (key === "date") {
347	      cmp = new Date(aa.createdAt).getTime() - new Date(bb.createdAt).getTime();
348	    } else if (key === "category") {
349	      cmp = aa.category.localeCompare(bb.category);
350	    } else if (key === "related") {
351	      cmp = (aa.referenceId ?? "").localeCompare(bb.referenceId ?? "");
352	    } else if (key === "subject") {
353	      cmp = aa.subject.localeCompare(bb.subject);
354	    } else if (key === "status") {
355	      cmp = aa.status.localeCompare(bb.status);
