"use client";

import { useTickets } from "@/shared/api/query-hooks/use-tickets";
import { APP_ROUTES } from "@/shared/config/app-routes";
import {
  ACTIVE_TICKET_STATUSES,
  ARCHIVE_TICKET_STATUSES,
  TICKET_CATEGORY_LABELS,
  TICKET_STATUS_LABELS,
} from "@/shared/constants/ticket";
import type { TicketListItem } from "@/shared/types/ticket.types";
import { TicketStatus } from "@/shared/types/ticket.types";
import { SupportSection } from "@/shared/ui/questions-enquiries-section";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/shared/ui/select";
import { Separator } from "@/shared/ui/shadcn/separator";
import { useSession } from "next-auth/react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { type ReactNode, Suspense, useState } from "react";

const STATUS_TEXT_COLORS: Record<TicketStatus, string> = {
  [TicketStatus.Open]: "text-[#059669]",
  [TicketStatus.Resolved]: "text-[#059669]",
  [TicketStatus.Rejected]: "text-[#DC2626]",
  [TicketStatus.Cancelled]: "text-[#6B7280]",
};

const STATUS_BADGE_CLASSES: Record<TicketStatus, { bg: string; text: string }> =
  {
    [TicketStatus.Open]: { bg: "bg-[#ecfdf5]", text: "text-[#047857]" },
    [TicketStatus.Resolved]: { bg: "bg-[#ecfdf5]", text: "text-[#047857]" },
    [TicketStatus.Rejected]: { bg: "bg-[#fee2e2]", text: "text-[#b91c1c]" },
    [TicketStatus.Cancelled]: { bg: "bg-[#f3f4f6]", text: "text-[#6b7280]" },
  };

type FilterValue = "all" | "active" | "archive";

function SupportPageContent() {
  const { status } = useSession();
  const isAuthenticated = status === "authenticated";
  const isSessionLoading = status === "loading";

  const router = useRouter();
  const [filter, setFilter] = useState<FilterValue>("all");

  function getStatuses() {
    if (filter === "active") return ACTIVE_TICKET_STATUSES;
    if (filter === "archive") return ARCHIVE_TICKET_STATUSES;
    return;
  }
  const statuses = getStatuses();

  const { data, isLoading } = useTickets({ statuses }, isAuthenticated);

  const tickets = data?.data ?? [];
  const ticketCount = data?.total ?? 0;

  return (
    <div className="flex flex-col">
      <div className="lg:min-h-[950px]">
        {/* Page header */}
        <div className="mt-8 flex items-center justify-between gap-4 sm:items-start">
          <h1 className="font-extralight font-new-serif text-4xl text-[#44403C] leading-[120%]">
            Support
          </h1>
          <Link
            className="inline-flex h-10 w-fit items-center gap-2 rounded border border-[#44403C] bg-transparent px-4 font-new-sans text-[#44403C] text-sm transition-colors hover:bg-[#EDE9E3]"
            href={APP_ROUTES.TICKETS.CREATE}
          >
            Raise Ticket
            <svg
              aria-hidden="true"
              fill="none"
              height="14"
              viewBox="0 0 14 14"
              width="14"
            >
              <path
                d="M7 1v12M1 7h12"
                stroke="currentColor"
                strokeLinecap="round"
                strokeWidth="1.5"
              />
            </svg>
          </Link>
        </div>

        <Separator className="my-10 hidden lg:block" />

        {/* Count + filter */}
        <div className="my-6 flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between lg:my-10">
          <div className="flex flex-col gap-0.5">
            <p className="font-medium font-new-sans text-[#44403C]">
              {isAuthenticated ? ticketCount : 0} Support Requests
            </p>
            <p className="font-new-sans text-[#A8A29E] text-sm">
              This is a record of all your Support Requests
            </p>
          </div>
          <Select
            disabled={!isAuthenticated}
            onValueChange={(val) => setFilter(val as FilterValue)}
            value={filter}
          >
            <SelectTrigger className="h-10 w-full rounded border border-[#D6D3D1] bg-[#F5F3EF] font-new-sans text-[#44403C] text-sm max-lg:hidden sm:w-[180px]">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">All Tickets</SelectItem>
              <SelectItem value="active">Active</SelectItem>
              <SelectItem value="archive">Archive</SelectItem>
            </SelectContent>
          </Select>
        </div>

        {/* Ticket list area */}
        <div className="mb-8 overflow-hidden rounded-xl border border-[#D6D3D1] bg-[#F5F3EF] lg:mb-16">
          <TicketListContent
            isAuthenticated={isAuthenticated}
            isLoading={isSessionLoading || (isAuthenticated && isLoading)}
            onTicketClick={(id) => router.push(`/support/${id}`)}
            tickets={tickets}
          />
        </div>
      </div>

      {/* Questions or enquiries — full bleed */}
      <div className="-mb-4 min-[1172px]:-mb-8 mr-[calc(-50vw+50%)] ml-[calc(-50vw+50%)]">
        <SupportSection />
      </div>
    </div>
  );
}

function TicketTableRow({
  ticket,
  onClick,
}: {
  ticket: TicketListItem;
  onClick: () => void;
}) {
  const ticketId = `Ticket${ticket.id.replace(/-/g, "").slice(0, 5).toUpperCase()}`;
  const date = new Date(ticket.createdAt).toLocaleDateString("en-AE", {
    day: "numeric",
    month: "short",
    year: "numeric",
  });

  return (
    <tr
      className="cursor-pointer border-[#E7E5E4] border-t transition-colors hover:bg-[#EDE9E3] lg:min-h-[84px]"
      onClick={onClick}
    >
      <td className="py-4 pr-3 pl-6 font-new-sans text-[#44403C] text-sm">
        {ticketId}
      </td>
      <td className="px-3 py-4 font-new-sans text-[#44403C] text-sm">{date}</td>
      <td className="px-3 py-4 font-new-sans text-[#44403C] text-sm">
        {TICKET_CATEGORY_LABELS[ticket.category]}
      </td>
      <td className="px-3 py-4 font-new-sans text-[#44403C] text-sm">
        {ticket.referenceId ?? "N/A"}
      </td>
      <td className="max-w-[320px] px-3 py-4">
        <span className="flex items-center gap-1.5 font-new-sans text-[#44403C] text-sm">
          <PaperclipIcon />
          <span className="truncate">{ticket.subject}</span>
        </span>
      </td>
      <td className="px-3 py-4">
        <span
          className={`font-medium font-new-sans text-sm ${STATUS_TEXT_COLORS[ticket.status]}`}
        >
          {TICKET_STATUS_LABELS[ticket.status]}
        </span>
      </td>
      <td className="py-4 pr-4 pl-3">
        <button
          aria-label="View ticket"
          className="flex size-8 items-center justify-center rounded-[6px] border border-[#D6D3D1] transition-colors hover:border-[#44403C]"
          onClick={onClick}
          type="button"
        >
          <svg
            aria-hidden="true"
            fill="none"
            height="14"
            viewBox="0 0 14 14"
            width="14"
          >
            <path
              d="M3 7h8M7.5 3.5L11 7l-3.5 3.5"
              stroke="#44403C"
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth="1.5"
            />
          </svg>
        </button>
      </td>
    </tr>
  );
}

function PaperclipIcon() {
  return (
    <svg
      aria-hidden="true"
      className="shrink-0 text-[#A8A29E]"
      fill="none"
      height="13"
      viewBox="0 0 24 24"
      width="13"
    >
      <path
        d="M21.44 11.05l-9.19 9.19a6 6 0 01-8.49-8.49l9.19-9.19a4 4 0 015.66 5.66l-9.2 9.19a2 2 0 01-2.83-2.83l8.49-8.48"
        stroke="currentColor"
        strokeLinecap="round"
        strokeLinejoin="round"
        strokeWidth="1.5"
      />
    </svg>
  );
}

function MobileTicketCard({
  ticket,
  onClick,
}: {
  ticket: TicketListItem;
  onClick: () => void;
}) {
  const ticketId = `Ticket${ticket.id.replace(/-/g, "").slice(0, 5).toUpperCase()}`;
  const badge = STATUS_BADGE_CLASSES[ticket.status];
  const statusLabel = TICKET_STATUS_LABELS[ticket.status];

  return (
    <div
      className="flex cursor-pointer flex-col gap-4 border-[#D6D3D1] border-b p-2 last:border-b-0"
      onClick={onClick}
    >
      <div className="flex items-center gap-2">
        <span
          className={`inline-flex shrink-0 items-center rounded-lg px-2 py-0.5 font-medium font-new-sans text-xs ${badge.bg} ${badge.text}`}
        >
          {statusLabel}
        </span>
        <span className="flex-1 font-new-sans text-[#44403C] text-sm">
          {ticketId}
        </span>
        <button
          aria-label="View ticket"
          className="flex shrink-0 items-center justify-center rounded-[6px] border border-[#A8A29E] p-1.5"
          onClick={onClick}
          type="button"
        >
          <svg
            aria-hidden="true"
            fill="none"
            height="14"
            viewBox="0 0 14 14"
            width="14"
          >
            <path
              d="M3 7h8M7.5 3.5L11 7l-3.5 3.5"
              stroke="#44403C"
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth="1.5"
            />
          </svg>
        </button>
      </div>
      <div className="flex items-start gap-2 py-1">
        <div className="mt-0.5 shrink-0">
          <PaperclipIcon />
        </div>
        <span className="font-new-sans text-[#44403C] text-sm">
          {ticket.subject}
        </span>
      </div>
    </div>
  );
}

function MobileTicketList({
  tickets,
  onTicketClick,
}: {
  tickets: TicketListItem[];
  onTicketClick: (id: string) => void;
}) {
  return (
    <div className="flex flex-col">
      <div
        className="flex items-center gap-2 border-[#D6D3D1] border-b p-2"
        style={{
          background:
            "linear-gradient(90deg, rgba(255,255,255,0.6) 0%, rgba(255,255,255,0.6) 100%), linear-gradient(90deg, #ede9e3 0%, #ede9e3 100%)",
        }}
      >
        <span className="font-new-sans text-sm">My Tickets</span>
      </div>
      {tickets.map((ticket) => (
        <MobileTicketCard
          key={ticket.id}
          onClick={() => onTicketClick(ticket.id)}
          ticket={ticket}
        />
      ))}
    </div>
  );
}

type SortKey = "date" | "category" | "related" | "subject" | "status";
type SortDir = "asc" | "desc";

interface ColumnDef {
  label: string;
  sortKey?: SortKey;
}

const COLUMNS: ColumnDef[] = [
  { label: "Ticket ID" },
  { label: "Date", sortKey: "date" },
  { label: "Issue Category", sortKey: "category" },
  { label: "Related", sortKey: "related" },
  { label: "Description", sortKey: "subject" },
  { label: "Status", sortKey: "status" },
  { label: "Actions" },
];

function sortTickets(
  tickets: TicketListItem[],
  key: SortKey,
  dir: SortDir
): TicketListItem[] {
  return [...tickets].sort((aa, bb) => {
    let cmp = 0;
    if (key === "date") {
      cmp = new Date(aa.createdAt).getTime() - new Date(bb.createdAt).getTime();
    } else if (key === "category") {
      cmp = aa.category.localeCompare(bb.category);
    } else if (key === "related") {
      cmp = (aa.referenceId ?? "").localeCompare(bb.referenceId ?? "");
    } else if (key === "subject") {
      cmp = aa.subject.localeCompare(bb.subject);
    } else if (key === "status") {
      cmp = aa.status.localeCompare(bb.status);
    }
    return dir === "asc" ? cmp : -cmp;
  });
}

function SortIcon({ active, dir }: { active: boolean; dir: SortDir }) {
  return (
    <svg
      aria-hidden="true"
      className="shrink-0"
      fill="none"
      height="12"
      viewBox="0 0 12 12"
      width="12"
    >
      <path
        d="M6 1v10M3 4l3-3 3 3"
        stroke={active && dir === "asc" ? "#44403C" : "#D6D3D1"}
        strokeLinecap="round"
        strokeLinejoin="round"
        strokeWidth="1.2"
      />
      <path
        d="M3 8l3 3 3-3"
        stroke={active && dir === "desc" ? "#44403C" : "#D6D3D1"}
        strokeLinecap="round"
        strokeLinejoin="round"
        strokeWidth="1.2"
      />
    </svg>
  );
}

function TicketListContent({
  isLoading,
  isAuthenticated,
  tickets,
  onTicketClick,
}: {
  isLoading: boolean;
  isAuthenticated: boolean;
  tickets: TicketListItem[];
  onTicketClick: (id: string) => void;
}) {
  const [sortKey, setSortKey] = useState<SortKey>("date");
  const [sortDir, setSortDir] = useState<SortDir>("desc");

  function handleSort(key: SortKey) {
    if (sortKey === key) {
      setSortDir((prev) => (prev === "asc" ? "desc" : "asc"));
    } else {
      setSortKey(key);
      setSortDir("asc");
    }
  }

  if (isLoading) return <TicketSkeleton />;
  if (!isAuthenticated) return <GuestEmptyState />;
  if (tickets.length === 0) return <AuthEmptyState />;

  const sorted = sortTickets(tickets, sortKey, sortDir);

  return (
    <>
      <div className="sm:hidden">
        <MobileTicketList onTicketClick={onTicketClick} tickets={sorted} />
      </div>
      <div className="hidden w-full overflow-x-auto sm:block">
        <table className="w-full min-w-[700px]">
          <thead>
            <tr className="border-[#E7E5E4] border-b">
              {COLUMNS.map((col) => (
                <th
                  className="py-3 pr-3 pl-6 text-left first:pl-6 last:pr-4"
                  key={col.label}
                >
                  {col.sortKey ? (
                    <button
                      className="flex items-center gap-1 font-medium font-new-sans text-[#A8A29E] text-xs transition-colors hover:text-[#44403C]"
                      onClick={() => handleSort(col.sortKey as SortKey)}
                      type="button"
                    >
                      {col.label}
                      <SortIcon
                        active={sortKey === col.sortKey}
                        dir={sortDir}
                      />
                    </button>
                  ) : (
                    <span className="font-medium font-new-sans text-[#A8A29E] text-xs">
                      {col.label}
                    </span>
                  )}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {sorted.map((ticket) => (
              <TicketTableRow
                key={ticket.id}
                onClick={() => onTicketClick(ticket.id)}
                ticket={ticket}
              />
            ))}
          </tbody>
        </table>
      </div>
    </>
  );
}

function TicketSkeleton() {
  return (
    <div className="flex flex-col gap-3 p-6">
      {[1, 2, 3].map((i) => (
        <div className="h-16 animate-pulse rounded-xl bg-[#EDE9E3]" key={i} />
      ))}
    </div>
  );
}

function EmptyStateWrapper({ children }: { children: ReactNode }) {
  return (
    <div className="flex flex-col items-center justify-center gap-3 bg-[#EDE9E3] px-6 py-16 text-center">
      <svg
        aria-hidden="true"
        fill="none"
        height="28"
        viewBox="0 0 24 24"
        width="28"
      >
        <path
          d="M10 13a5 5 0 007.54.54l3-3a5 5 0 00-7.07-7.07l-1.72 1.71"
          stroke="#A8A29E"
          strokeLinecap="round"
          strokeLinejoin="round"
          strokeWidth="1.5"
        />
        <path
          d="M14 11a5 5 0 00-7.54-.54l-3 3a5 5 0 007.07 7.07l1.71-1.71"
          stroke="#A8A29E"
          strokeLinecap="round"
          strokeLinejoin="round"
          strokeWidth="1.5"
        />
      </svg>
      {children}
    </div>
  );
}

function GuestEmptyState() {
  return (
    <EmptyStateWrapper>
      <div className="flex flex-col gap-1">
        <p className="font-medium font-new-sans text-[#A8A29E]">
          Nothing to see here yet
        </p>
        <p className="font-new-sans text-sm">
          Login to see your created support tickets
        </p>
      </div>
    </EmptyStateWrapper>
  );
}

function AuthEmptyState() {
  return (
    <EmptyStateWrapper>
      <div className="flex flex-col gap-1">
        <p className="font-medium font-new-sans text-[#A8A29E]">
          We are up to date
        </p>
        <p className="font-new-sans text-[#A8A29E] text-sm">
          You don’t have support tickets yet.
        </p>
      </div>
    </EmptyStateWrapper>
  );
}

