"use client";

import { signOut } from "next-auth/react";
import { usePathname, useRouter } from "next/navigation";
import type { ReactNode } from "react";

import { APP_ROUTES } from "@/shared/config/app-routes";
import { SELLER_SIDEBAR_ITEMS } from "@/shared/config/sidebar-config";
import { useSidebarContext } from "@/shared/contexts/sidebar-context";
import { Sidebar } from "@/shared/ui/sidebar";

const NEW_DESIGN_ROUTES = [
  "/wallet",
  "/quote-request/create",
  "/my-offers",
  "/quote-request",
  "/buybacks",
  "/tickets",
  "/welcome",
];

export default function SidebarLayout({ children }: { children: ReactNode }) {
  const router = useRouter();
  const pathname = usePathname();
  const { isOpen, setIsOpen } = useSidebarContext();

  const isBuybackPayPage =
    pathname.startsWith("/buybacks/") && pathname.endsWith("/pay");

  if (
    NEW_DESIGN_ROUTES.some((route) => pathname.startsWith(route)) ||
    isBuybackPayPage
  ) {
    return <>{children}</>;
  }

  function getActiveItem() {
    for (const item of SELLER_SIDEBAR_ITEMS) {
      if (item.path === pathname) {
        return item.value;
      }

      if (item.subItems) {
        for (const subItem of item.subItems) {
          if (subItem.path === pathname) {
            return subItem.value;
          }
        }
      }
    }

    for (const item of SELLER_SIDEBAR_ITEMS) {
      if (item.subItems) {
        for (const subItem of item.subItems) {
          const basePath = subItem.path.split("?")[0];
          if (
            pathname.startsWith(basePath) &&
            (pathname[basePath.length] === "?" ||
              pathname[basePath.length] === "/" ||
              pathname.length === basePath.length)
          ) {
            return subItem.value;
          }
        }
      }
    }

    const firstSegment = pathname.split("/")[1];

    return firstSegment || "profile";
  }

  const _isNewDesign = NEW_DESIGN_ROUTES.some(
    (route) => pathname === route || pathname.startsWith(`${route}/`)
  );

  const activeItem = getActiveItem();

  async function handleItemClick(value: string, path?: string) {
    if (value === "logout") {
      await signOut({ redirect: false });
      router.push(APP_ROUTES.AUTH.SIGN_IN);
      router.refresh();

      return;
    }

    if (path && path !== "#") {
      router.push(path);
    }
  }

  const isFullWidthPage = pathname === APP_ROUTES.PROFILE;

  if (isFullWidthPage) {
    return <>{children}</>;
  }

  return (
    <div className="flex min-h-full w-full flex-col md:flex-row">
      <Sidebar
        activeItem={activeItem}
        isOpen={isOpen}
        items={SELLER_SIDEBAR_ITEMS}
        onItemClick={handleItemClick}
        onOpenChange={setIsOpen}
      />
      <div className="flex-1 px-3 pt-4 pb-6 sm:px-4 sm:pt-8 lg:max-w-[calc(100vw-266px)] lg:pt-8">
        {children}
      </div>
    </div>
  );
}

